// Logout endpoint
app.get('/auth/logout', (req, res) => {
  const sessionId = req.cookies?.session_id;
  if (sessionId && sessions[sessionId]) {
    delete sessions[sessionId];
  }
  res.clearCookie('session_id');
  res.redirect('/');
});

